unitsize(0.05cm);
label("Blue eyes", (2,74));
label("Blond hair", (80,74));
label("Neither: 3", (44,10));
draw(Circle((30,45), 22));
draw(Circle((58, 45), 22));
label("$6$", (44, 45));
label(scale(0.8)*"$x-6$",(28,58));
label(scale(0.8)*"$2x-6$",(63,58));
[/asy]

